import React from "react";
import { Link } from "react-router-dom";
import Logo from "../assets/travel.jpg"
import toast from "react-hot-toast";

const Navbar = (props)=> {
    let isLoggedIn = props.isLoggedIn;
    let setIsLoggedIn = props.setIsLoggedIn;


    return (
        <div className="flex justify-evenly item-center w-11/12 max-w-[1160px] py-4 mx-auto v">
            <Link to="/">
             
             <img src= {Logo} alt="Logo" width={40} height={32} loading="lazy"></img> 
            </Link>
            <nav>
                <ul className="text-white flex gap-x-6 ">
                    <li>
                        <Link to="/" className=" hover:text-gray-300">Home</Link>
                    </li>
                    <li>
                        <Link to="/" className=" hover:text-gray-300">about</Link>
                    </li>
                    <li>
                        <Link to="/" className=" hover:text-gray-300">contact us</Link>
                    </li>
                     <li>
                        <Link to="/planTrip">Plan trip</Link>
                    </li>
                </ul>
            </nav>

            {/* login-signin-logout-dashboard */}

            <div className="flex item-center gap-x-4 text-white">
                  { !isLoggedIn &&
                    <Link to="/login">
                        <button className="bg-richblack-800 py-[8px] px-[14px] 
                        rounded-[8px] border border-yellow-700" >Login</button>
                    </Link>
                  }
                  { !isLoggedIn &&
                    <Link to="/signup" >
                        <button className="bg-richblack-800 py-[8px] px-[14px] 
                        rounded-[8px] border border-yellow-700" >Sign up</button>
                    </Link>
                  }
                  { isLoggedIn &&
                    <Link to="/">
                        <button className="bg-richblack-800 py-[6px] px-[14px] 
                        rounded-[8px] border border-yellow-700"  onClick={()=>{
                            setIsLoggedIn(false);
                            toast.success("logged Out");
                        }}>Logout</button>
                    </Link>
                  }
                  { isLoggedIn &&
                    <Link to="/dashboard">
                        <button className="bg-richblack-800 py-[6px] px-[14px] 
                        rounded-[8px] border border-yellow-700">Dashboard</button>
                    </Link>
                  }




            </div>

        </div>
    )
}

export default Navbar;
